// @ts-nocheck
import"./bootstrap";import{createApp}from"vue";import Toast from"vue-toastification";import"vue-toastification/dist/index.css";import Marketplace from"./components/Marketplace.vue";import SkinDetails from"./components/SkinDetails.vue";import Profile from"./components/Profile.vue";import Cart from"./components/Cart.vue";import CartButton from"./components/CartButton.vue";import Header from"./components/Header.vue";import FavoriteButton from"./components/FavoriteButton.vue";import"./footer-accordion.js";import"./loader.js";import"./custom-swiper.js";import"./script.js";const toastOptions={position:"bottom-right",timeout:8e3,closeOnClick:!0,pauseOnFocusLoss:!0,pauseOnHover:!0,draggable:!0,draggablePercent:.6,showCloseButtonOnHover:!1,hideProgressBar:!1,closeButton:"button",icon:!0,rtl:!1,maxToasts:5,newestOnTop:!0};document.addEventListener("DOMContentLoaded",(()=>{const t=document.getElementById("marketplace-app");if(t){const e=createApp(Marketplace,{initialListings:JSON.parse(t.dataset.listings||"[]"),initialTotal:parseInt(t.dataset.total||"0"),initialHasMore:"true"===t.dataset.hasMore});e.use(Toast,toastOptions),e.mount("#marketplace-app")}const e=document.getElementById("skin-details-app");if(e){const t=parseInt(e.dataset.listingId),o=createApp(SkinDetails,{listingId:t});o.use(Toast,toastOptions),o.mount("#skin-details-app")}const o=document.getElementById("profile-app");if(o){const t=createApp(Profile,{initialClient:JSON.parse(o.dataset.client||"{}"),telegramBotName:o.dataset.telegramBotName||""});t.use(Toast,toastOptions),window.telegramBotName=o.dataset.telegramBotName||"",t.mount("#profile-app")}if(document.getElementById("cart-app")){const t=createApp(Cart);t.use(Toast,toastOptions),t.mount("#cart-app")}!function t(){const e=document.getElementById("header-app");if(e)try{const t="null"!==e.dataset.user?JSON.parse(e.dataset.user):null,o=JSON.parse(e.dataset.routes),a=e.dataset.logoUrl,s=createApp(Header,{user:t,routes:o,logoUrl:a});s.use(Toast,toastOptions),s.mount("#header-app")}catch(t){console.error("Error mounting header:",t)}else setTimeout(t,100)}();document.querySelectorAll("[data-cart-button]").forEach((t=>{const e=parseInt(t.dataset.listingId),o=t.dataset.size||"normal",a=t.dataset.variant||"primary";if(e){const s=createApp(CartButton,{listingId:e,size:o,variant:a});s.use(Toast,toastOptions),s.mount(t)}}));document.querySelectorAll("[data-favorite-button]").forEach((t=>{const e=parseInt(t.dataset.listingId);if(e){const o=createApp(FavoriteButton,{listingId:e});o.use(Toast,toastOptions),o.mount(t)}}))}));